import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)",
];

const ROUTER_ABI = [
  "function getAmountsOut(uint256 amountIn, address[] calldata path) external view returns (uint256[] memory amounts)",
  "function swapExactTokensForTokens(uint256 amountIn,uint256 amountOutMin,address[] calldata path,address to,uint256 deadline) external returns (uint256[] memory amounts)",
];

const MAX_UINT256 = ethers.MaxUint256;

export class TokenSwapDApp {
  constructor({
    provider,
    routerAddress,
    account = null,
    erc20Abi = ERC20_ABI,
    routerAbi = ROUTER_ABI,
  }) {
    this.provider = provider;
    this.routerAddress = routerAddress;
    this.erc20Abi = erc20Abi;
    this.routerAbi = routerAbi;
    this.account = account;
    this.signer = null;
    this.router = null;
  }

  async init() {
    if (!this.provider) throw new Error("Provider is required");
    if (typeof this.provider.send === "function") {
      try {
        await this.provider.send("eth_requestAccounts", []);
      } catch (_) {}
    }
    const browserProvider =
      this.provider instanceof ethers.BrowserProvider
        ? this.provider
        : new ethers.BrowserProvider(this.provider);
    this.provider = browserProvider;
    this.signer = await this.provider.getSigner();
    this.account = this.account || (await this.signer.getAddress());
    this.router = new ethers.Contract(
      this.routerAddress,
      this.routerAbi,
      this.signer
    );
    return this;
  }

  getTokenContract(tokenAddress, withSigner = true) {
    return new ethers.Contract(
      tokenAddress,
      this.erc20Abi,
      withSigner ? this.signer : this.provider
    );
  }

  async getTokenMetadata(tokenAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    const [symbol, decimals] = await Promise.all([
      token.symbol(),
      token.decimals(),
    ]);
    return { symbol, decimals };
  }

  async getBalance(tokenAddress, owner = this.account) {
    const token = this.getTokenContract(tokenAddress, false);
    return await token.balanceOf(owner);
  }

  async getAllowance(tokenAddress, owner = this.account, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    return await token.allowance(owner, spender);
  }

  async approveMax(tokenAddress, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, true);
    const tx = await token.approve(spender, MAX_UINT256);
    const receipt = await tx.wait();
    return { tx, receipt, approvedAmount: MAX_UINT256 };
  }

  async ensureApproval(tokenAddress, amountIn, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, this.account, spender);
    if (allowance >= amountIn) {
      return { approved: true, skipped: true, allowance };
    }
    const approval = await this.approveMax(tokenAddress, spender);
    return { approved: true, skipped: false, allowanceBefore: allowance, ...approval };
  }

  async getAmountsOut(amountIn, path) {
    return await this.router.getAmountsOut(amountIn, path);
  }

  calculateAmountOutMin(expectedOut, slippageBps = 50n) {
    const bpsDenominator = 10000n;
    return (expectedOut * (bpsDenominator - slippageBps)) / bpsDenominator;
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    slippageBps = 50n,
    recipient = this.account,
    deadlineSeconds = 60 * 20,
    autoApprove = true,
    path = null,
  }) {
    if (!this.router || !this.signer) {
      throw new Error("DApp not initialized. Call init() first.");
    }

    const swapPath = path || [tokenIn, tokenOut];

    if (autoApprove) {
      await this.ensureApproval(tokenIn, amountIn, this.routerAddress);
    }

    const amountsOut = await this.getAmountsOut(amountIn, swapPath);
    const expectedOut = amountsOut[amountsOut.length - 1];
    const amountOutMin = this.calculateAmountOutMin(expectedOut, BigInt(slippageBps));
    const deadline = Math.floor(Date.now() / 1000) + deadlineSeconds;

    const tx = await this.router.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      swapPath,
      recipient,
      deadline
    );

    const receipt = await tx.wait();

    return {
      tx,
      receipt,
      path: swapPath,
      amountIn,
      expectedOut,
      amountOutMin,
      recipient,
      deadline,
    };
  }

  async quoteSwap({
    tokenIn,
    tokenOut,
    amountIn,
    path = null,
    slippageBps = 50n,
  }) {
    const swapPath = path || [tokenIn, tokenOut];
    const amounts = await this.getAmountsOut(amountIn, swapPath);
    const expectedOut = amounts[amounts.length - 1];
    const amountOutMin = this.calculateAmountOutMin(expectedOut, BigInt(slippageBps));
    return {
      path: swapPath,
      amountIn,
      amounts,
      expectedOut,
      amountOutMin,
      slippageBps: BigInt(slippageBps),
    };
  }

  async parseAmount(tokenAddress, humanReadableAmount) {
    const { decimals } = await this.getTokenMetadata(tokenAddress);
    return ethers.parseUnits(String(humanReadableAmount), decimals);
  }

  async formatAmount(tokenAddress, rawAmount) {
    const { decimals } = await this.getTokenMetadata(tokenAddress);
    return ethers.formatUnits(rawAmount, decimals);
  }
}

export async function createTokenSwapDApp({
  injectedProvider = window.ethereum,
  routerAddress,
}) {
  const app = new TokenSwapDApp({
    provider: injectedProvider,
    routerAddress,
  });
  await app.init();
  return app;
}

export async function exampleUsage() {
  const routerAddress = "0xRouterAddress";
  const tokenIn = "0xTokenInAddress";
  const tokenOut = "0xTokenOutAddress";

  const app = await createTokenSwapDApp({ routerAddress });

  const amountIn = await app.parseAmount(tokenIn, "1.0");

  const quote = await app.quoteSwap({
    tokenIn,
    tokenOut,
    amountIn,
    slippageBps: 100n,
  });

  const approvalResult = await app.ensureApproval(tokenIn, amountIn);

  const swapResult = await app.swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    slippageBps: 100n,
    autoApprove: false,
  });

  return { quote, approvalResult, swapResult };
}